+const placeChildren = (node: DOMElement, columnCount: number): Map<DOMElement, Placement> => {
+	const placements = new Map<DOMElement, Placement>();
+	const occupied = new Set<string>();
+	let cursorColumn = 1;
+	let cursorRow = 1;
