+	for (const child of node.childNodes) {
+		if (child.nodeName === 'ink-virtual-text' || !child.yogaNode) continue;
+		const [columnStart, columnEnd] = parseLine(child.style.gridColumn);
+		const [rowStart, rowEnd] = parseLine(child.style.gridRow);
+		const column = columnStart ?? cursorColumn;
+		const row = rowStart ?? cursorRow;
+		const endColumn = columnEnd ?? column + 1;
+		const endRow = rowEnd ?? row + 1;
+
+		for (let y = row; y < endRow; y++) {
+			for (let x = column; x < endColumn; x++) occupied.add(`${x}:${y}`);
+		}
+
+		placements.set(child, {column, columnEnd: endColumn, row, rowEnd: endRow});
+		if (columnStart === undefined && rowStart === undefined) {
